// Konfiguracja zespołów i ich List ID
const teams = [
  { name: 'Hostessy', listId: 'LIST_ID_HOSTESSY', managerId: 'user@email.com' },
  { name: 'Rejestracja', listId: 'LIST_ID_REJESTRACJA', managerId: 'manager2@email.com' },
  { name: 'Logistyka', listId: 'LIST_ID_LOGISTYKA', managerId: 'manager3@email.com' },
  { name: 'Ochrona', listId: 'LIST_ID_OCHRONA', managerId: 'manager4@email.com' },
  { name: 'Catering', listId: 'LIST_ID_CATERING', managerId: 'manager5@email.com' },
  { name: 'VIP', listId: 'LIST_ID_VIP', managerId: 'manager6@email.com' }
];

const now = new Date();
const currentHour = now.getHours();

// Określ jakie sprawdzenia robić o której godzinie
const checks = {
  checkRejestracja: currentHour >= 8 && currentHour < 9,
  checkPolowkowy: currentHour === 13,
  checkKoncowy: currentHour >= 17 && currentHour < 18,
  checkProduktow: currentHour >= 10 && currentHour < 11
};

return teams.map(team => ({
  json: {
    ...team,
    ...checks,
    currentHour,
    timestamp: now.toISOString()
  }
}));

const teamData = $('Przygotuj Konfigurację Zespołów').item.json;
const tasks = $input.first().json.tasks || [];

// Analiza tasków
const niezarejestrowani = [];
const bezRaportuPolowkowego = [];
const bezRaportuKoncowego = [];
const problemy = [];
const statystyki = {
  lacznie: tasks.length,
  zrobione: 0,
  wTrakcie: 0,
  nierozpoczete: 0
};

tasks.forEach(task => {
  // Zlicz statusy
  if (task.status.status === 'complete') statystyki.zrobione++;
  else if (task.status.status === 'in progress') statystyki.wTrakcie++;
  else statystyki.nierozpoczete++;

  const customFields = {};
  (task.custom_fields || []).forEach(cf => {
    customFields[cf.name.toLowerCase().replace(/ /g, '_')] = cf.value;
  });

  // Sprawdź rejestrację
  if (teamData.checkRejestracja && !customFields.godzina_przyjscia) {
    niezarejestrowani.push({
      taskId: task.id,
      nazwa: task.name,
      email: customFields.email
    });
  }

  // Sprawdź raport połówkowy
  if (teamData.checkPolowkowy && !customFields.raport_polowkowy) {
    bezRaportuPolowkowego.push({
      taskId: task.id,
      nazwa: task.name,
      email: customFields.email
    });
  }

  // Sprawdź raport końcowy
  if (teamData.checkKoncowy && !customFields.raport_koncowy) {
    bezRaportuKoncowego.push({
      taskId: task.id,
      nazwa: task.name,
      email: customFields.email
    });
  }

  // Sprawdź stan produktów (jeśli poniżej 10)
  if (customFields.stan_produktow && parseInt(customFields.stan_produktow) < 10) {
    problemy.push({
      taskId: task.id,
      nazwa: task.name,
      problem: `Mało produktów: ${customFields.stan_produktow} szt`,
      pilne: true
    });
  }
});

const maProblem = niezarejestrowani.length > 0 || 
                  bezRaportuPolowkowego.length > 0 || 
                  bezRaportuKoncowego.length > 0 || 
                  problemy.length > 0;

return [{
  json: {
    ...teamData,
    analizaTaskow: {
      niezarejestrowani,
      bezRaportuPolowkowego,
      bezRaportuKoncowego,
      problemy,
      statystyki
    },
    maProblem,
    liczbaProblemow: niezarejestrowani.length + bezRaportuPolowkowego.length + 
                     bezRaportuKoncowego.length + problemy.length
  }
}];

const data = $input.first().json;
const analiza = data.analizaTaskow;

// Buduj treść emaila
let emailBody = `
<html>
<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
<h2 style="color: #e74c3c;">⚠️ Alert - Zespół: ${data.name}</h2>
<p>Czas: ${new Date().toLocaleTimeString('pl-PL')}</p>

<div style="background: #f8f9fa; padding: 15px; border-radius: 8px; margin: 10px 0;">
  <h3>📊 Statystyki zespołu</h3>
  <ul>
    <li>Łącznie osób: ${analiza.statystyki.lacznie}</li>
    <li>✅ Skończyły: ${analiza.statystyki.zrobione}</li>
    <li>⏳ W trakcie: ${analiza.statystyki.wTrakcie}</li>
    <li>❌ Nie zaczęły: ${analiza.statystyki.nierozpoczete}</li>
  </ul>
</div>
`;

if (analiza.niezarejestrowani.length > 0) {
  emailBody += `
<div style="background: #fff3cd; padding: 15px; border-radius: 8px; margin: 10px 0; border-left: 4px solid #ffc107;">
  <h3>🚫 Nie zarejestrowały się (${analiza.niezarejestrowani.length} osób)</h3>
  <ul>
    ${analiza.niezarejestrowani.map(p => `<li>${p.nazwa}</li>`).join('')}
  </ul>
</div>`;
}

if (analiza.bezRaportuPolowkowego.length > 0) {
  emailBody += `
<div style="background: #fff3cd; padding: 15px; border-radius: 8px; margin: 10px 0; border-left: 4px solid #fd7e14;">
  <h3>📋 Brak raportu połówkowego (${analiza.bezRaportuPolowkowego.length} osób)</h3>
  <ul>
    ${analiza.bezRaportuPolowkowego.map(p => `<li>${p.nazwa}</li>`).join('')}
  </ul>
</div>`;
}

if (analiza.problemy.length > 0) {
  emailBody += `
<div style="background: #f8d7da; padding: 15px; border-radius: 8px; margin: 10px 0; border-left: 4px solid #dc3545;">
  <h3>🚨 Pilne Problemy (${analiza.problemy.length})</h3>
  <ul>
    ${analiza.problemy.map(p => `<li><strong>${p.nazwa}</strong>: ${p.problem}</li>`).join('')}
  </ul>
</div>`;
}

emailBody += `
<hr>
<p style="color: #666; font-size: 12px;">Automatyczny alert z systemu n8n | ${new Date().toLocaleString('pl-PL')}</p>
</body>
</html>`;

return [{
  json: {
    ...data,
    emailSubject: `⚠️ [${data.name}] ${data.liczbaProblemow} problemów wymaga uwagi`,
    emailBody,
    managerEmail: data.managerId
  }
}];

// Wysyłaj powiadomienia do konkretnych osób które nie wykonały zadań
const data = $input.first().json;
const analiza = data.analizaTaskow;

// Zbierz wszystkich którzy wymagają przypomnienia
const doWyslania = [
  ...analiza.niezarejestrowani.map(p => ({ ...p, typ: 'rejestracja', wiadomosc: 'Nie zarejestrowałaś swojego przybycia. Zrób to natychmiast!' })),
  ...analiza.bezRaportuPolowkowego.map(p => ({ ...p, typ: 'raport_polowkowy', wiadomosc: 'Nie wypełniłaś raportu połówkowego (13:00). Zrób to teraz!' })),
  ...analiza.bezRaportuKoncowego.map(p => ({ ...p, typ: 'raport_koncowy', wiadomosc: 'Nie wypełniłaś raportu końcowego. Wymagane przed wyjściem!' }))
];

return doWyslania.map(osoba => ({
  json: {
    taskId: osoba.taskId,
    email: osoba.email,
    nazwa: osoba.nazwa,
    typ: osoba.typ,
    wiadomosc: osoba.wiadomosc,
    teamName: data.name
  }
}));

// Lista wszystkich zespołów
const teams = [
  { 
    name: 'Hostessy', 
    listId: 'LIST_ID_HOSTESSY', 
    managerEmail: 'manager1@email.com',
    typProduktu: 'Coca-Cola (puszki)'
  },
  { 
    name: 'Rejestracja', 
    listId: 'LIST_ID_REJESTRACJA', 
    managerEmail: 'manager2@email.com',
    typProduktu: 'Identyfikatory'
  },
  { 
    name: 'Logistyka', 
    listId: 'LIST_ID_LOGISTYKA', 
    managerEmail: 'manager3@email.com',
    typProduktu: 'Paczki'
  },
  { 
    name: 'Ochrona', 
    listId: 'LIST_ID_OCHRONA', 
    managerEmail: 'manager4@email.com',
    typProduktu: 'Przepustki'
  },
  { 
    name: 'Catering', 
    listId: 'LIST_ID_CATERING', 
    managerEmail: 'manager5@email.com',
    typProduktu: 'Posiłki'
  },
  { 
    name: 'VIP', 
    listId: 'LIST_ID_VIP', 
    managerEmail: 'manager6@email.com',
    typProduktu: 'VIP Pakiety'
  }
];

const today = new Date();
const dateStr = today.toLocaleDateString('pl-PL');

return teams.map(team => ({
  json: { 
    ...team, 
    dateStr,
    timestamp: today.toISOString()
  }
}));

const teamConfig = $('Konfiguracja Wszystkich Zespołów').item.json;
const tasks = $input.first().json.tasks || [];

// Przetworz dane każdego taska
const pracownicy = tasks.map(task => {
  const customFields = {};
  (task.custom_fields || []).forEach(cf => {
    customFields[cf.name.toLowerCase().replace(/ /g, '_')] = cf.value;
  });

  return {
    id: task.id,
    nazwa: task.name.split(' - Dyżur')[0], // Wyciągnij samo imię
    status: task.status.status,
    godzinaPrzyjscia: customFields.godzina_przyjscia || 'BRAK',
    godzinaClosure: customFields.godzina_zamkniecia || 'BRAK',
    zarejestrowala: customFields.zarejestrowala === 'true',
    stanPoczatkowy: parseInt(customFields.stan_poczatkowy) || 0,
    stanKoncowy: parseInt(customFields.stan_koncowy) || 0,
    rozdane: (parseInt(customFields.stan_poczatkowy) || 0) - (parseInt(customFields.stan_koncowy) || 0),
    raportWypelniony: !!customFields.raport_koncowy,
    raportTresc: customFields.raport_koncowy || '',
    uwagi: customFields.uwagi || '',
    email: customFields.email || ''
  };
});

// Statystyki ogólne
const stats = {
  lacznie: pracownicy.length,
  obecne: pracownicy.filter(p => p.godzinaPrzyjscia !== 'BRAK').length,
  nieobecne: pracownicy.filter(p => p.godzinaPrzyjscia === 'BRAK').length,
  zRaportem: pracownicy.filter(p => p.raportWypelniony).length,
  bezRaportu: pracownicy.filter(p => !p.raportWypelniony).length,
  zarejestrowane: pracownicy.filter(p => p.zarejestrowala).length,
  lacznie_produktow: pracownicy.reduce((sum, p) => sum + p.rozdane, 0),
  srednia_produktow: pracownicy.length > 0 
    ? Math.round(pracownicy.reduce((sum, p) => sum + p.rozdane, 0) / pracownicy.length) 
    : 0
};

// Znajdź osoby z problemami
const problemy = {
  bezRaportu: pracownicy.filter(p => !p.raportWypelniony && p.godzinaPrzyjscia !== 'BRAK'),
  nieobecne: pracownicy.filter(p => p.godzinaPrzyjscia === 'BRAK'),
  maloProduktuRozdale: pracownicy.filter(p => p.rozdane < 5 && p.godzinaPrzyjscia !== 'BRAK')
};

return [{
  json: {
    ...teamConfig,
    pracownicy,
    stats,
    problemy,
    maProblemy: problemy.bezRaportu.length > 0 || problemy.nieobecne.length > 0
  }
}];

const data = $input.first().json.body || $input.first().json;

// Mapowanie zespołów
const teamListMap = {
  'hostessy': 'WPISZ_LIST_ID_HOSTESSY',
  'rejestracja': 'WPISZ_LIST_ID_REJESTRACJA',
  'logistyka': 'WPISZ_LIST_ID_LOGISTYKA',
  'ochrona': 'WPISZ_LIST_ID_OCHRONA',
  'catering': 'WPISZ_LIST_ID_CATERING',
  'vip': 'WPISZ_LIST_ID_VIP'
};

const zespol = (data.zespol || '').toLowerCase().trim();
const listId = teamListMap[zespol] || null;

// Walidacja
const errors = [];
if (!data.imie_nazwisko) errors.push('Brak imienia i nazwiska');
if (!data.zespol) errors.push('Brak zespołu');
if (!listId) errors.push('Nieznany zespół: ' + zespol);

// Godzina przyjścia
const now = new Date();
const godzina = data.godzina_przyjscia || 
  now.getHours().toString().padStart(2,'0') + ':' + 
  now.getMinutes().toString().padStart(2,'0');

// Sprawdź spóźnienie (planowane 8:00)
const [h, m] = godzina.split(':').map(Number);
const minutyPrzyjscia = h * 60 + m;
const minutyPlanowane = 8 * 60;
const spoznienie = minutyPrzyjscia - minutyPlanowane;

const dataFormatted = now.toLocaleDateString('pl-PL');

return [{
  json: {
    imie_nazwisko: data.imie_nazwisko || '',
    email: data.email || '',
    zespol: data.zespol || '',
    telefon: data.telefon || '',
    listId,
    godzina,
    spoznienie,
    czyPunktualna: spoznienie <= 0,
    czySpozniona: spoznienie > 15,
    errors,
    isValid: errors.length === 0,
    dataFormatted,
    timestamp: now.toISOString()
  }
}];

const walidacja = $('Walidacja Danych').item.json;
const task = $input.first().json;

// Zapisz task ID do użycia w kolejnych nodach
return [{
  json: {
    taskId: task.id,
    taskUrl: task.url,
    imie_nazwisko: walidacja.imie_nazwisko,
    email: walidacja.email,
    zespol: walidacja.zespol,
    listId: walidacja.listId,
    godzina: walidacja.godzina,
    czySpozniona: walidacja.czySpozniona,
    spoznienie: walidacja.spoznienie,
    dataFormatted: walidacja.dataFormatted
  }
}];

